"use client";

import {
  memo,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_STORY_VIEWER_LABELS,
  type StoryViewer01Handle,
  type StoryViewer01Labels,
  type StoryViewer01Props,
} from "./types";
import { useStoryViewerState } from "./hooks/use-story-viewer-state";
import { useStoryProgress } from "./hooks/use-story-progress";
import { useStoryKeyboardNav } from "./hooks/use-story-keyboard-nav";
import { ViewerShell } from "./parts/viewer-shell";
import { ProgressBars } from "./parts/progress-bars";
import { ViewerHeader } from "./parts/viewer-header";
import { TapZones } from "./parts/tap-zones";
import { NavArrows } from "./parts/nav-arrows";
import { ItemView } from "./parts/item-view";

interface StoryViewer01InnerProps extends StoryViewer01Props {
  ref?: React.Ref<StoryViewer01Handle>;
}

function StoryViewer01Inner(props: StoryViewer01InnerProps) {
  const {
    stories: initialStories,
    initialStoryIndex,
    isOpen,
    onClose,
    ref,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    renderItem,
    defaultItemDuration = 5,
    labels: labelsProp,
    className,
    contentClassName,
  } = props;

  const labels = useMemo<Required<StoryViewer01Labels>>(
    () => ({ ...DEFAULT_STORY_VIEWER_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const {
    stories,
    cursor,
    isPaused,
    isMuted,
    setPaused,
    setMuted,
    goToPrevItem,
    goToNextItem,
    goToPrevStory,
    goToNextStory,
    goToStoryIndex,
    goToItemIndex,
    reset,
    dispatch,
  } = useStoryViewerState({
    initialStories,
    initialStoryIndex,
    isOpen,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    onClose,
  });

  const currentStory = stories[cursor.storyIndex];
  const currentItem = currentStory?.items[cursor.itemIndex];

  // Imperative handle.
  const storiesRef = useRef(stories);
  const cursorRef = useRef(cursor);
  useEffect(() => {
    storiesRef.current = stories;
    cursorRef.current = cursor;
  });
  useImperativeHandle(
    ref,
    () => ({
      goToStory: goToStoryIndex,
      goToItem: goToItemIndex,
      setPaused: (paused: boolean) => setPaused(paused),
      getCursor: () => ({
        storyIndex: cursorRef.current.storyIndex,
        itemIndex: cursorRef.current.itemIndex,
      }),
      getCurrentStories: () => storiesRef.current,
      reset,
      dispatch,
    }),
    [goToStoryIndex, goToItemIndex, setPaused, reset, dispatch],
  );

  // Per-item video metadata duration cache.
  const [videoMetadataMs, setVideoMetadataMs] = useState<Record<string, number>>({});
  const handleVideoMetadata = useCallback(
    (duration: number) => {
      if (!currentItem) return;
      if (!Number.isFinite(duration) || duration <= 0) return;
      setVideoMetadataMs((prev) => {
        if (prev[currentItem.id] != null) return prev;
        return { ...prev, [currentItem.id]: duration * 1000 };
      });
    },
    [currentItem],
  );

  // Resolve item duration (R-Plan-4): explicit → video metadata → default.
  const itemDurationMs = useMemo(() => {
    if (!currentItem) return defaultItemDuration * 1000;
    if (currentItem.duration != null) return currentItem.duration * 1000;
    if (currentItem.type === "video") {
      const meta = videoMetadataMs[currentItem.id];
      if (meta != null) return meta;
    }
    return defaultItemDuration * 1000;
  }, [currentItem, videoMetadataMs, defaultItemDuration]);

  const itemKey = currentStory && currentItem
    ? `${currentStory.id}:${currentItem.id}`
    : "";

  const progress = useStoryProgress({
    isOpen: isOpen && !!currentItem,
    isPaused,
    itemKey,
    itemDurationMs,
    onComplete: goToNextItem,
  });

  // Keyboard nav (Escape funnels through Radix → onOpenChange).
  useStoryKeyboardNav({
    isOpen,
    onPrevItem: goToPrevItem,
    onNextItem: goToNextItem,
    onTogglePause: () => setPaused((p) => !p),
  });

  const handleOpenChange = useCallback(
    (open: boolean) => {
      if (!open) onClose();
    },
    [onClose],
  );

  if (!currentStory || !currentItem) {
    // Render the shell so closing animations still fire when stories empty mid-view.
    return (
      <ViewerShell
        isOpen={isOpen}
        onOpenChange={handleOpenChange}
        ariaLabel={labels.viewerLabel}
        className={contentClassName}
      >
        <span />
      </ViewerShell>
    );
  }

  return (
    <ViewerShell
      isOpen={isOpen}
      onOpenChange={handleOpenChange}
      ariaLabel={labels.viewerLabel}
      className={contentClassName}
    >
      <NavArrows
        canPrev={cursor.storyIndex > 0}
        onPrev={goToPrevStory}
        onNext={goToNextStory}
        labels={labels}
      />

      <div className={cn("relative h-full w-full bg-black", className)}>
        <ProgressBars
          items={currentStory.items}
          currentItemIndex={cursor.itemIndex}
          progress={progress}
        />
        <ViewerHeader
          story={currentStory}
          item={currentItem}
          isPaused={isPaused}
          isMuted={isMuted}
          onTogglePause={() => setPaused((p) => !p)}
          onToggleMute={() => setMuted((m) => !m)}
          onClose={onClose}
          formatTime={labels.formatTime}
          labels={labels}
        />
        <ItemView
          item={currentItem}
          story={currentStory}
          totalItems={currentStory.items.length}
          cursor={cursor}
          isPaused={isPaused}
          isMuted={isMuted}
          onLoadedMetadata={handleVideoMetadata}
          onEnded={goToNextItem}
          renderItem={renderItem}
          labels={labels}
        />
        <TapZones
          onPrev={goToPrevItem}
          onTogglePause={() => setPaused((p) => !p)}
          onNext={goToNextItem}
        />
      </div>
    </ViewerShell>
  );
}

const StoryViewer01 = memo(StoryViewer01Inner);
StoryViewer01.displayName = "StoryViewer01";

export { StoryViewer01 };

export { StoryViewer01 } from "./story-viewer-01";

export {
  storyViewerReducer,
  useStoryViewerState,
  type UseStoryViewerStateOptions,
  type UseStoryViewerStateResult,
} from "./hooks/use-story-viewer-state";

export {
  useStoryProgress,
  type UseStoryProgressOptions,
} from "./hooks/use-story-progress";

export {
  useStoryKeyboardNav,
  type UseStoryKeyboardNavOptions,
} from "./hooks/use-story-keyboard-nav";

export type {
  Story,
  StoryItem,
  StoryViewer01Props,
  StoryViewer01Handle,
  StoryViewer01Labels,
  StoryViewerDelta,
  StoryViewerLocalAction,
  RenderItemContext,
  Subscribe,
  Unsubscribe,
} from "./types";

export { DEFAULT_STORY_VIEWER_LABELS } from "./types";

import type { ReactNode } from "react";

// ─── Data shapes ────────────────────────────────────────────────────────

export interface StoryItem {
  id: string;
  type: "image" | "video";
  src: string;
  /** Display duration in seconds. Default 5 for images; for videos, viewer reads the actual duration via onLoadedMetadata. */
  duration?: number;
}

export interface Story {
  id: string;
  /** Stable user id — useful for cross-rail wiring. */
  userId: string;
  username: string;
  avatar?: string;
  items: StoryItem[];
  hasUnread?: boolean;
  /** ISO date string (matches the pro-ui convention from event-card-01 / content-card-news-01). */
  createdAt: string;
}

// ─── Realtime contract ──────────────────────────────────────────────────

export type Unsubscribe = () => void;
export type Subscribe<TDelta> = (handler: (delta: TDelta) => void) => Unsubscribe;

export type StoryViewerDelta =
  | { kind: "story-added"; story: Story; position?: "start" | "end" }
  | { kind: "story-removed"; storyId: string }
  | { kind: "item-added"; storyId: string; item: StoryItem; position?: "start" | "end" }
  | { kind: "item-removed"; storyId: string; itemId: string }
  | { kind: "story-viewed"; storyId: string };

export type StoryViewerLocalAction =
  | { kind: "add-story"; story: Story; position?: "start" | "end" }
  | { kind: "remove-story"; storyId: string }
  | { kind: "add-item"; storyId: string; item: StoryItem; position?: "start" | "end" }
  | { kind: "remove-item"; storyId: string; itemId: string }
  | { kind: "patch-story"; storyId: string; partial: Partial<Story> }
  | { kind: "subscribe-delta"; delta: StoryViewerDelta }
  | { kind: "reset"; next: Story[] };

// ─── Render-prop helpers ────────────────────────────────────────────────

export interface RenderItemContext {
  storyIndex: number;
  itemIndex: number;
  isPaused: boolean;
  isMuted: boolean;
}

// ─── i18n ───────────────────────────────────────────────────────────────

export interface StoryViewer01Labels {
  /** aria-label for the modal. Default: "Story viewer". */
  viewerLabel?: string;
  /** aria-label for the play button (when paused). Default: "Play". */
  play?: string;
  /** aria-label for the pause button (when playing). Default: "Pause". */
  pause?: string;
  /** aria-label for the mute button (when audio is on). Default: "Mute". */
  mute?: string;
  /** aria-label for the unmute button (when audio is off). Default: "Unmute". */
  unmute?: string;
  /** aria-label for the close button. Default: "Close". */
  close?: string;
  /** aria-label for the previous-story arrow. Default: "Previous story". */
  prevStory?: string;
  /** aria-label for the next-story arrow. Default: "Next story". */
  nextStory?: string;
  /** Format the relative time shown in the header. */
  formatTime?: (date: Date) => string;
  /** Default alt text for image items. */
  itemImageAlt?: (story: Story, itemIndex: number, totalItems: number) => string;
}

export const DEFAULT_STORY_VIEWER_LABELS: Required<StoryViewer01Labels> = {
  viewerLabel: "Story viewer",
  play: "Play",
  pause: "Pause",
  mute: "Mute",
  unmute: "Unmute",
  close: "Close",
  prevStory: "Previous story",
  nextStory: "Next story",
  formatTime: (date: Date) =>
    new Intl.DateTimeFormat(undefined, { hour: "2-digit", minute: "2-digit" }).format(date),
  itemImageAlt: (story: Story, idx: number, total: number) =>
    `${story.username}, story image ${idx + 1} of ${total}`,
};

// ─── Imperative handle ──────────────────────────────────────────────────

export interface StoryViewer01Handle {
  /** Jump to a specific story by index (item index resets to 0). */
  goToStory: (index: number) => void;
  /** Jump to a specific item within the current story. */
  goToItem: (index: number) => void;
  /** Force pause/resume from outside (matches the in-component pause state). */
  setPaused: (paused: boolean) => void;
  /** Read current navigation cursor. */
  getCursor: () => { storyIndex: number; itemIndex: number };
  /** Read current stories snapshot (post-realtime patches). */
  getCurrentStories: () => Story[];
  /** Re-seed external state push (always-uncontrolled escape hatch). */
  reset: (next: Story[]) => void;
  /** Surgical state edit. */
  dispatch: (action: StoryViewerLocalAction) => void;
}

// ─── Props ──────────────────────────────────────────────────────────────

export interface StoryViewer01Props {
  /** Story list. **Mount-only** — subsequent prop changes are ignored; push updates via `ref.current.reset(next)` or `dispatch`. */
  stories: Story[];
  /** Which story to open (item always starts at 0). */
  initialStoryIndex: number;
  /** Controlled open state. */
  isOpen: boolean;
  /** Fires on Escape, backdrop click, close button, or auto-close at end of last story. */
  onClose: () => void;
  /** Imperative handle. */
  ref?: React.Ref<StoryViewer01Handle>;

  // ─── Realtime ──────────────────────────────────────────────────────────
  /** Live source. Memoize via useCallback over a stable channel ref; identity changes trigger clean teardown + re-call. Mount-scoped. */
  subscribe?: Subscribe<StoryViewerDelta>;
  /** Fires for every delta; useful for analytics / cross-component coordination. */
  onSubscribeDelta?: (delta: StoryViewerDelta) => void;

  // ─── Lifecycle callbacks ──────────────────────────────────────────────
  /** Forward-completion only — fires when the user advances forward into the next story OR when the last item completes naturally. Does NOT fire on backward navigation (matches Instagram). */
  onStoryViewed?: (storyId: string) => void;
  /** Fires when an item completes naturally OR is navigated past forward. */
  onItemViewed?: (storyId: string, itemId: string, itemIndex: number) => void;
  /** Fires whenever the cursor moves (manual nav or auto-advance). */
  onCursorChange?: (storyIndex: number, itemIndex: number) => void;
  /** Fires synchronously immediately before `onClose()` when the auto-close triggers at end of the last story. */
  onAutoCloseAtEnd?: () => void;

  // ─── Slots ─────────────────────────────────────────────────────────────
  /** Custom item renderer. When provided, replaces the default branching on item.type. Hosts using this MUST set `item.duration` explicitly for non-video items. */
  renderItem?: (item: StoryItem, context: RenderItemContext) => ReactNode;

  // ─── Defaults ──────────────────────────────────────────────────────────
  /** Default item duration in seconds when neither item.duration nor video metadata is available. Default 5. */
  defaultItemDuration?: number;

  // ─── i18n ──────────────────────────────────────────────────────────────
  labels?: StoryViewer01Labels;

  // ─── Style overrides ──────────────────────────────────────────────────
  /** Extra classes for the inner content wrapper. */
  className?: string;
  /** Extra classes for the modal content surface. */
  contentClassName?: string;
}

import { Dialog, DialogContent, DialogTitle } from "@/components/ui/dialog";
import { cn } from "@/lib/utils";

export interface ViewerShellProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  ariaLabel: string;
  className?: string;
  children: React.ReactNode;
}

/**
 * Modal surface — owns the v0.1 CSS animation seam and the Radix
 * Dialog wiring. v0.2 will swap pure CSS for framer-motion drag="y"
 * for swipe-to-dismiss; this is the single file that changes.
 */
export function ViewerShell({
  isOpen,
  onOpenChange,
  ariaLabel,
  className,
  children,
}: ViewerShellProps) {
  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent
        showCloseButton={false}
        aria-label={ariaLabel}
        className={cn(
          // Reset shadcn defaults: no card chrome, no padding, no ring, no rounded.
          "block gap-0 overflow-hidden bg-black p-0 text-white ring-0",
          // Mobile: full screen.
          "h-dvh w-screen max-w-none rounded-none",
          // Desktop: portrait modal centered (kasder-exact 400×700).
          "md:h-175 md:w-100 md:max-w-100 md:rounded-2xl",
          className,
        )}
      >
        <DialogTitle className="sr-only">{ariaLabel}</DialogTitle>
        {children}
      </DialogContent>
    </Dialog>
  );
}

import type { StoryItem } from "../types";

export interface ProgressBarsProps {
  items: StoryItem[];
  currentItemIndex: number;
  /** Current item progress percentage (0–100). */
  progress: number;
}

export function ProgressBars({ items, currentItemIndex, progress }: ProgressBarsProps) {
  return (
    <div className="absolute left-0 right-0 top-0 z-20 flex gap-1 p-2">
      {items.map((item, idx) => {
        const width =
          idx < currentItemIndex
            ? 100
            : idx === currentItemIndex
              ? progress
              : 0;
        return (
          <div
            key={item.id}
            className="h-0.5 flex-1 overflow-hidden rounded-full bg-white/30"
            role="progressbar"
            aria-valuemin={0}
            aria-valuemax={100}
            aria-valuenow={Math.round(width)}
          >
            <div
              className="h-full bg-white transition-[width] duration-100 ease-linear"
              style={{ width: `${width}%` }}
            />
          </div>
        );
      })}
    </div>
  );
}

import { Pause, Play, Volume2, VolumeX, X } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import type { Story, StoryItem, StoryViewer01Labels } from "../types";

export interface ViewerHeaderProps {
  story: Story;
  item: StoryItem;
  isPaused: boolean;
  isMuted: boolean;
  onTogglePause: () => void;
  onToggleMute: () => void;
  onClose: () => void;
  formatTime: (date: Date) => string;
  labels: Required<StoryViewer01Labels>;
}

export function ViewerHeader({
  story,
  item,
  isPaused,
  isMuted,
  onTogglePause,
  onToggleMute,
  onClose,
  formatTime,
  labels,
}: ViewerHeaderProps) {
  const initials = story.username.slice(0, 2).toUpperCase();
  return (
    <div className="absolute left-0 right-0 top-4 z-20 flex items-center justify-between px-4 pt-2">
      <div className="flex items-center gap-3">
        <Avatar className="h-10 w-10 border-2 border-white">
          {story.avatar ? <AvatarImage src={story.avatar} alt="" /> : null}
          <AvatarFallback>{initials}</AvatarFallback>
        </Avatar>
        <div>
          <p className="text-sm font-semibold text-white">{story.username}</p>
          <p className="text-xs text-white/60">
            {formatTime(new Date(story.createdAt))}
          </p>
        </div>
      </div>
      <div className="flex items-center gap-2">
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="h-8 w-8 text-white hover:bg-white/20 hover:text-white"
          onClick={onTogglePause}
          aria-label={isPaused ? labels.play : labels.pause}
        >
          {isPaused ? <Play className="h-4 w-4" /> : <Pause className="h-4 w-4" />}
        </Button>
        {item.type === "video" ? (
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-8 w-8 text-white hover:bg-white/20 hover:text-white"
            onClick={onToggleMute}
            aria-label={isMuted ? labels.unmute : labels.mute}
            aria-pressed={isMuted}
          >
            {isMuted ? <VolumeX className="h-4 w-4" /> : <Volume2 className="h-4 w-4" />}
          </Button>
        ) : null}
        <Button
          type="button"
          variant="ghost"
          size="icon"
          className="h-8 w-8 text-white hover:bg-white/20 hover:text-white"
          onClick={onClose}
          aria-label={labels.close}
        >
          <X className="h-5 w-5" />
        </Button>
      </div>
    </div>
  );
}

export interface TapZonesProps {
  onPrev: () => void;
  onTogglePause: () => void;
  onNext: () => void;
}

/**
 * Three full-height columns (1/3 each) over the item content:
 * - left = previous item
 * - middle = pause toggle
 * - right = next item
 *
 * Lives at z-10 so the header (z-20) and nav arrows (z-20) remain clickable.
 * `tabIndex={-1}` because tap zones are touch affordances; keyboard users
 * use the arrow-key handlers instead.
 */
export function TapZones({ onPrev, onTogglePause, onNext }: TapZonesProps) {
  return (
    <div className="absolute inset-0 z-10 flex" aria-hidden="true">
      <button
        type="button"
        className="h-full w-1/3 cursor-pointer"
        onClick={(e) => {
          e.stopPropagation();
          onPrev();
        }}
        tabIndex={-1}
      />
      <button
        type="button"
        className="h-full w-1/3 cursor-pointer"
        onClick={(e) => {
          e.stopPropagation();
          onTogglePause();
        }}
        tabIndex={-1}
      />
      <button
        type="button"
        className="h-full w-1/3 cursor-pointer"
        onClick={(e) => {
          e.stopPropagation();
          onNext();
        }}
        tabIndex={-1}
      />
    </div>
  );
}

import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { StoryViewer01Labels } from "../types";

export interface NavArrowsProps {
  canPrev: boolean;
  onPrev: () => void;
  onNext: () => void;
  labels: Required<StoryViewer01Labels>;
}

/**
 * Desktop-only story-level nav (← → between stories).
 * Hidden on mobile; tap zones cover same-story item nav there.
 */
export function NavArrows({ canPrev, onPrev, onNext, labels }: NavArrowsProps) {
  const base =
    "absolute top-1/2 z-30 hidden h-12 w-12 -translate-y-1/2 rounded-full bg-white/10 text-white hover:bg-white/20 hover:text-white md:flex md:items-center md:justify-center";
  return (
    <>
      <Button
        type="button"
        variant="ghost"
        size="icon"
        className={cn(base, "left-4")}
        onClick={(e) => {
          e.stopPropagation();
          onPrev();
        }}
        disabled={!canPrev}
        aria-label={labels.prevStory}
      >
        <ChevronLeft className="h-8 w-8" />
      </Button>
      <Button
        type="button"
        variant="ghost"
        size="icon"
        className={cn(base, "right-4")}
        onClick={(e) => {
          e.stopPropagation();
          onNext();
        }}
        aria-label={labels.nextStory}
      >
        <ChevronRight className="h-8 w-8" />
      </Button>
    </>
  );
}

import { VideoPlayer01 } from "../../video-player-01";
import type {
  RenderItemContext,
  Story,
  StoryItem,
  StoryViewer01Labels,
} from "../types";

export interface ItemViewProps {
  item: StoryItem;
  story: Story;
  totalItems: number;
  cursor: { storyIndex: number; itemIndex: number };
  isPaused: boolean;
  isMuted: boolean;
  onLoadedMetadata: (duration: number) => void;
  onEnded: () => void;
  renderItem?: (item: StoryItem, context: RenderItemContext) => React.ReactNode;
  labels: Required<StoryViewer01Labels>;
}

export function ItemView({
  item,
  story,
  totalItems,
  cursor,
  isPaused,
  isMuted,
  onLoadedMetadata,
  onEnded,
  renderItem,
  labels,
}: ItemViewProps) {
  if (renderItem) {
    return (
      <div className="absolute inset-0 flex items-center justify-center">
        {renderItem(item, {
          storyIndex: cursor.storyIndex,
          itemIndex: cursor.itemIndex,
          isPaused,
          isMuted,
        })}
      </div>
    );
  }

  if (item.type === "image") {
    return (
      <div className="absolute inset-0 flex items-center justify-center">
        <img
          src={item.src}
          alt={labels.itemImageAlt(story, cursor.itemIndex, totalItems)}
          className="h-full w-full object-cover"
        />
      </div>
    );
  }

  return (
    <div className="absolute inset-0">
      <VideoPlayer01
        key={item.id}
        src={item.src}
        isActive={!isPaused}
        muted={isMuted}
        loop={false}
        autoPlay
        controls={false}
        objectFit="cover"
        className="h-full w-full"
        videoClassName="h-full w-full"
        onLoadedMetadata={onLoadedMetadata}
        onEnded={onEnded}
      />
    </div>
  );
}

"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useReducer,
  useRef,
  useState,
} from "react";
import type {
  Story,
  StoryItem,
  StoryViewerDelta,
  StoryViewerLocalAction,
  Subscribe,
} from "../types";

// ─── Pure helpers ────────────────────────────────────────────────────────────

function insertStoryAtPosition(
  state: Story[],
  story: Story,
  position: "start" | "end" | undefined,
): Story[] {
  if (position === "start") return [story, ...state];
  return [...state, story]; // default "end" — cursor-stable for ID-anchored cursor
}

function removeStoryById(state: Story[], id: string): Story[] {
  const next = state.filter((s) => s.id !== id);
  return next.length === state.length ? state : next;
}

function patchStoryById(
  state: Story[],
  id: string,
  patch: Partial<Story>,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== id) return s;
    mutated = true;
    return { ...s, ...patch };
  });
  return mutated ? next : state;
}

function addItemToStory(
  state: Story[],
  storyId: string,
  item: StoryItem,
  position: "start" | "end" | undefined,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== storyId) return s;
    mutated = true;
    const items = position === "start" ? [item, ...s.items] : [...s.items, item];
    return { ...s, items };
  });
  return mutated ? next : state;
}

function removeItemFromStory(
  state: Story[],
  storyId: string,
  itemId: string,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== storyId) return s;
    const items = s.items.filter((i) => i.id !== itemId);
    if (items.length === s.items.length) return s;
    mutated = true;
    return { ...s, items };
  });
  return mutated ? next : state;
}

// ─── Reducer ─────────────────────────────────────────────────────────────────

/** Pure reducer — exported for hosts driving their own state. */
export function storyViewerReducer(
  state: Story[],
  action: StoryViewerLocalAction,
): Story[] {
  switch (action.kind) {
    case "add-story":
      return insertStoryAtPosition(state, action.story, action.position);
    case "remove-story":
      return removeStoryById(state, action.storyId);
    case "add-item":
      return addItemToStory(state, action.storyId, action.item, action.position);
    case "remove-item":
      return removeItemFromStory(state, action.storyId, action.itemId);
    case "patch-story":
      return patchStoryById(state, action.storyId, action.partial);
    case "subscribe-delta": {
      const d = action.delta;
      switch (d.kind) {
        case "story-added":
          return insertStoryAtPosition(state, d.story, d.position);
        case "story-removed":
          return removeStoryById(state, d.storyId);
        case "item-added":
          return addItemToStory(state, d.storyId, d.item, d.position);
        case "item-removed":
          return removeItemFromStory(state, d.storyId, d.itemId);
        case "story-viewed":
          return patchStoryById(state, d.storyId, { hasUnread: false });
      }
      return state;
    }
    case "reset":
      return action.next;
  }
}

// ─── Internal cursor (ID-anchored) ──────────────────────────────────────────

interface CursorIds {
  storyId: string;
  itemId: string;
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export interface UseStoryViewerStateOptions {
  /** Captured ON MOUNT only — subsequent prop changes are ignored. */
  initialStories: Story[];
  /** Re-seeds cursor whenever (initialStoryIndex, isOpen) pair changes. */
  initialStoryIndex: number;
  /** Re-seeds cursor whenever (initialStoryIndex, isOpen) pair changes. */
  isOpen: boolean;

  subscribe?: Subscribe<StoryViewerDelta>;
  onSubscribeDelta?: (delta: StoryViewerDelta) => void;

  onStoryViewed?: (storyId: string) => void;
  onItemViewed?: (storyId: string, itemId: string, itemIndex: number) => void;
  onCursorChange?: (storyIndex: number, itemIndex: number) => void;
  onAutoCloseAtEnd?: () => void;
  onClose: () => void;
}

export interface UseStoryViewerStateResult {
  stories: Story[];
  /** Public derived cursor (indices for caller; IDs are internal). */
  cursor: { storyIndex: number; itemIndex: number };
  isPaused: boolean;
  isMuted: boolean;
  setPaused: React.Dispatch<React.SetStateAction<boolean>>;
  setMuted: React.Dispatch<React.SetStateAction<boolean>>;
  goToPrevItem: () => void;
  goToNextItem: () => void;
  goToPrevStory: () => void;
  goToNextStory: () => void;
  goToStoryIndex: (index: number) => void;
  goToItemIndex: (index: number) => void;
  reset: (next: Story[]) => void;
  dispatch: React.Dispatch<StoryViewerLocalAction>;
}

export function useStoryViewerState(
  opts: UseStoryViewerStateOptions,
): UseStoryViewerStateResult {
  const {
    initialStories,
    initialStoryIndex,
    isOpen,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    onClose,
  } = opts;

  const [stories, dispatch] = useReducer(storyViewerReducer, initialStories);

  const initialStoriesRef = useRef(stories);
  useEffect(() => {
    initialStoriesRef.current = stories;
  });

  // Refs-mirror for callbacks so effect deps stay narrow.
  const onSubscribeDeltaRef = useRef(onSubscribeDelta);
  const onStoryViewedRef = useRef(onStoryViewed);
  const onItemViewedRef = useRef(onItemViewed);
  const onCursorChangeRef = useRef(onCursorChange);
  const onAutoCloseAtEndRef = useRef(onAutoCloseAtEnd);
  const onCloseRef = useRef(onClose);
  useEffect(() => {
    onSubscribeDeltaRef.current = onSubscribeDelta;
    onStoryViewedRef.current = onStoryViewed;
    onItemViewedRef.current = onItemViewed;
    onCursorChangeRef.current = onCursorChange;
    onAutoCloseAtEndRef.current = onAutoCloseAtEnd;
    onCloseRef.current = onClose;
  });

  // Subscribe wiring (mount-scoped; identity-stable per host convention).
  useEffect(() => {
    if (!subscribe) return;
    const unsub = subscribe((delta) => {
      onSubscribeDeltaRef.current?.(delta);
      dispatch({ kind: "subscribe-delta", delta });
    });
    return unsub;
  }, [subscribe]);

  // ─── Cursor state (ID-anchored) ───────────────────────────────────────────
  // Lazy initializer — runs once at mount, derived from props.
  const [cursorIds, setCursorIds] = useState<CursorIds>(() => {
    const idx = Math.max(0, Math.min(initialStoryIndex, initialStories.length - 1));
    const story = initialStories[idx];
    return {
      storyId: story?.id ?? "",
      itemId: story?.items[0]?.id ?? "",
    };
  });

  // Reset cursor when (initialStoryIndex, isOpen) pair changes.
  // Read stories from ref to keep deps narrow.
  useEffect(() => {
    if (!isOpen) return;
    const snap = initialStoriesRef.current;
    const idx = Math.max(0, Math.min(initialStoryIndex, snap.length - 1));
    const story = snap[idx];
    if (!story) return;
    setCursorIds({
      storyId: story.id,
      itemId: story.items[0]?.id ?? "",
    });
  }, [initialStoryIndex, isOpen]);

  // Derive indices from IDs.
  const cursor = useMemo(() => {
    const storyIndex = Math.max(0, stories.findIndex((s) => s.id === cursorIds.storyId));
    const story = stories[storyIndex];
    const itemIndex = story
      ? Math.max(0, story.items.findIndex((i) => i.id === cursorIds.itemId))
      : 0;
    return { storyIndex, itemIndex };
  }, [stories, cursorIds]);

  // Fire onCursorChange whenever derived indices change.
  const lastCursorRef = useRef(cursor);
  useEffect(() => {
    const last = lastCursorRef.current;
    if (last.storyIndex !== cursor.storyIndex || last.itemIndex !== cursor.itemIndex) {
      lastCursorRef.current = cursor;
      onCursorChangeRef.current?.(cursor.storyIndex, cursor.itemIndex);
    }
  }, [cursor]);

  // ─── Pause / mute ────────────────────────────────────────────────────────
  const [isPaused, setPaused] = useState(false);
  const [isMuted, setMuted] = useState(true);

  // Reset pause on item key change — React 19 pattern: setState during render
  // when a derived prop changes. Keeps resume from sticking after auto-advance.
  const itemKey = `${cursorIds.storyId}:${cursorIds.itemId}`;
  const [renderedItemKey, setRenderedItemKey] = useState(itemKey);
  if (renderedItemKey !== itemKey) {
    setRenderedItemKey(itemKey);
    setPaused(false);
  }

  // ─── Navigation helpers ──────────────────────────────────────────────────
  const goToPrevItem = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = story.items.findIndex((i) => i.id === cursorIds.itemId);
    if (iIdx > 0) {
      setCursorIds({ storyId: story.id, itemId: story.items[iIdx - 1].id });
      return;
    }
    if (sIdx > 0) {
      const prevStory = snap[sIdx - 1];
      const lastItem = prevStory.items[prevStory.items.length - 1];
      if (lastItem) {
        setCursorIds({ storyId: prevStory.id, itemId: lastItem.id });
      }
    }
    // else: at the very start; no-op.
  }, [cursorIds]);

  const goToNextItem = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = story.items.findIndex((i) => i.id === cursorIds.itemId);
    const item = story.items[iIdx];
    if (item) {
      onItemViewedRef.current?.(story.id, item.id, iIdx);
    }
    if (iIdx < story.items.length - 1) {
      setCursorIds({ storyId: story.id, itemId: story.items[iIdx + 1].id });
      return;
    }
    // At last item — advance to next story (forward).
    onStoryViewedRef.current?.(story.id);
    if (sIdx < snap.length - 1) {
      const nextStory = snap[sIdx + 1];
      const firstItem = nextStory.items[0];
      if (firstItem) {
        setCursorIds({ storyId: nextStory.id, itemId: firstItem.id });
        return;
      }
    }
    // No next story — auto-close.
    onAutoCloseAtEndRef.current?.();
    onCloseRef.current();
  }, [cursorIds]);

  const goToPrevStory = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx <= 0) return;
    const prevStory = snap[sIdx - 1];
    const firstItem = prevStory.items[0];
    if (firstItem) {
      // Backward — does NOT fire onStoryViewed.
      setCursorIds({ storyId: prevStory.id, itemId: firstItem.id });
    }
  }, [cursorIds]);

  const goToNextStory = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    onStoryViewedRef.current?.(story.id);
    if (sIdx < snap.length - 1) {
      const nextStory = snap[sIdx + 1];
      const firstItem = nextStory.items[0];
      if (firstItem) {
        setCursorIds({ storyId: nextStory.id, itemId: firstItem.id });
        return;
      }
    }
    onAutoCloseAtEndRef.current?.();
    onCloseRef.current();
  }, [cursorIds]);

  const goToStoryIndex = useCallback((index: number) => {
    const snap = initialStoriesRef.current;
    const sIdx = Math.max(0, Math.min(index, snap.length - 1));
    const target = snap[sIdx];
    if (!target) return;
    const currentSIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    // Forward jump — fire onStoryViewed for the leaving story.
    if (sIdx > currentSIdx && currentSIdx >= 0) {
      onStoryViewedRef.current?.(snap[currentSIdx].id);
    }
    setCursorIds({
      storyId: target.id,
      itemId: target.items[0]?.id ?? "",
    });
  }, [cursorIds]);

  const goToItemIndex = useCallback((index: number) => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = Math.max(0, Math.min(index, story.items.length - 1));
    const item = story.items[iIdx];
    if (!item) return;
    setCursorIds({ storyId: story.id, itemId: item.id });
  }, [cursorIds]);

  const reset = useCallback((next: Story[]) => {
    dispatch({ kind: "reset", next });
  }, []);

  return {
    stories,
    cursor,
    isPaused,
    isMuted,
    setPaused,
    setMuted,
    goToPrevItem,
    goToNextItem,
    goToPrevStory,
    goToNextStory,
    goToStoryIndex,
    goToItemIndex,
    reset,
    dispatch,
  };
}

"use client";

import { useEffect, useRef, useState } from "react";

export interface UseStoryProgressOptions {
  /** Viewer is mounted-and-open. When false, timer is fully stopped. */
  isOpen: boolean;
  /** When true, the timer pauses but accumulator is preserved (resume continues from same %). */
  isPaused: boolean;
  /** Compound key — typically `${storyId}:${itemId}`. Any change resets the accumulator. */
  itemKey: string;
  /** Total item duration in milliseconds. */
  itemDurationMs: number;
  /** Fires once when progress reaches 100. */
  onComplete: () => void;
  /** Tick interval. Default 50ms. */
  tickMs?: number;
}

/**
 * Accumulator-based story progress timer.
 *
 * Tracks an `accumulatedMs` accumulator across pause/resume cycles so users
 * can pause for arbitrary durations without losing playback position.
 * Naive `Date.now() - startTime` recomputes (kasder's original pattern) silently
 * advance ~50ms per pause/resume cycle. Switched to `performance.now()` here
 * for monotonic clock + immunity to NTP / DST jumps.
 */
export function useStoryProgress({
  isOpen,
  isPaused,
  itemKey,
  itemDurationMs,
  onComplete,
  tickMs = 50,
}: UseStoryProgressOptions) {
  const [progress, setProgress] = useState(0);
  const [renderedItemKey, setRenderedItemKey] = useState(itemKey);
  const accumulatedRef = useRef(0);
  const startTimeRef = useRef<number | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const completedRef = useRef(false);
  const onCompleteRef = useRef(onComplete);

  useEffect(() => {
    onCompleteRef.current = onComplete;
  });

  // Reset on item change — React 19 pattern: setState during render when
  // a derivable prop changes. Refs get reset in the effect below.
  if (renderedItemKey !== itemKey) {
    setRenderedItemKey(itemKey);
    setProgress(0);
  }

  // Refs reset on item change — runs before the timer effect (declaration order).
  useEffect(() => {
    accumulatedRef.current = 0;
    completedRef.current = false;
  }, [itemKey]);

  useEffect(() => {
    if (!isOpen) {
      // Fully stop on close.
      accumulatedRef.current = 0;
      startTimeRef.current = null;
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }

    if (isPaused) {
      // Snapshot elapsed into accumulator + clear interval.
      if (startTimeRef.current !== null) {
        accumulatedRef.current += performance.now() - startTimeRef.current;
        startTimeRef.current = null;
      }
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }

    // Run.
    startTimeRef.current = performance.now();
    intervalRef.current = setInterval(() => {
      const startedAt = startTimeRef.current;
      if (startedAt === null) return;
      const elapsed = performance.now() - startedAt + accumulatedRef.current;
      const pct = Math.min((elapsed / itemDurationMs) * 100, 100);
      setProgress(pct);
      if (pct >= 100 && !completedRef.current) {
        completedRef.current = true;
        accumulatedRef.current = 0;
        startTimeRef.current = null;
        if (intervalRef.current !== null) {
          clearInterval(intervalRef.current);
          intervalRef.current = null;
        }
        onCompleteRef.current();
      }
    }, tickMs);

    return () => {
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [isOpen, isPaused, itemKey, itemDurationMs, tickMs]);

  return progress;
}

"use client";

import { useEffect, useRef } from "react";

export interface UseStoryKeyboardNavOptions {
  isOpen: boolean;
  onPrevItem: () => void;
  onNextItem: () => void;
  onTogglePause: () => void;
  /** Optional — Radix Dialog already handles Escape via `onOpenChange`; supply only if you want a parallel hook. */
  onClose?: () => void;
}

/**
 * Window-scoped keyboard handlers for the story viewer.
 *
 * - ArrowLeft → onPrevItem
 * - ArrowRight → onNextItem
 * - Space → onTogglePause (preventDefault to stop page scroll)
 * - Escape → onClose (when supplied; deduplicated with Radix Dialog)
 *
 * Listener attaches on `isOpen=true` only and detaches on close — no leaks.
 * Refs-mirror pattern keeps the listener stable; only re-attaches on `isOpen` flip.
 */
export function useStoryKeyboardNav(opts: UseStoryKeyboardNavOptions) {
  const refs = useRef(opts);
  useEffect(() => {
    refs.current = opts;
  });

  const { isOpen } = opts;
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      switch (e.key) {
        case "ArrowLeft":
          refs.current.onPrevItem();
          break;
        case "ArrowRight":
          refs.current.onNextItem();
          break;
        case " ":
          e.preventDefault();
          refs.current.onTogglePause();
          break;
        case "Escape":
          refs.current.onClose?.();
          break;
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [isOpen]);
}

export function defaultFormatTime(date: Date): string {
  return new Intl.DateTimeFormat(undefined, {
    hour: "2-digit",
    minute: "2-digit",
  }).format(date);
}
